<?php include 'includes/config.php'; require_role('seller'); $u=current_user(); if(isset($_POST['order_id'],$_POST['status'])){$pdo->prepare('UPDATE orders SET status=? WHERE id=? AND seller_id=?')->execute([clean($_POST['status']),(int)$_POST['order_id'],$u['id']]);} ?>
<!DOCTYPE html><html><head><title>Seller Sales</title><link rel="stylesheet" href="css/styles.css"></head><body><?php include 'includes/header.php'; ?><section class="section"><h1>My Sales and Product Tracking</h1><table class="table"><tr><th>Order</th><th>Buyer</th><th>Total</th><th>Delivery</th><th>Status</th><th>Update</th><th>Days</th></tr>
<?php $stmt=$pdo->prepare('SELECT o.*,u.full_name buyer FROM orders o JOIN users u ON o.buyer_id=u.id WHERE o.seller_id=? ORDER BY o.created_at DESC');$stmt->execute([$u['id']]);foreach($stmt as $o): $days=floor((time()-strtotime($o['created_at']))/86400); ?><tr><td>#<?= $o['id'] ?></td><td><?= clean($o['buyer']) ?></td><td>R<?= number_format($o['total'],2) ?></td><td><?= clean($o['delivery_method']) ?></td><td><?= clean($o['status']) ?></td><td><form method="post"><input type="hidden" name="order_id" value="<?= $o['id'] ?>"><select name="status"><option>proof_uploaded</option><option>confirmed</option><option>packed</option><option>sent_to_pep</option><option>ready_for_collection</option><option>completed</option></select><button>Save</button></form></td><td><?= $days ?> days</td></tr><?php endforeach; ?></table></section></body></html>
